    public function fetch_currencies($params = array ()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * fetches all available currencies on an exchange
             *
             * @see https://apidocs.lighter.xyz/reference/assetdetails
             *
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} an associative dictionary of currencies
             */
            $response = Async\await($this->publicGetAssetDetails ($params));
            if ($this->check_required_credentials(false)) {
                Async\await($this->pre_load_lighter_library());
            }
            //
            //     {
            //         "code" => 200,
            //         "asset_details" => array(
            //             {
            //                 "asset_id" => 3,
            //                 "symbol" => "USDC",
            //                 "l1_decimals" => 6,
            //                 "decimals" => 6,
            //                 "min_transfer_amount" => "1.000000",
            //                 "min_withdrawal_amount" => "1.000000",
            //                 "margin_mode" => "enabled",
            //                 "index_price" => "1.000000",
            //                 "l1_address" => "0x95Fd23d5110f9D89A4b0B7d63D78F5B5Ea5074D1"
            //             }
            //         )
            //     }
            //
            $data = $this->safe_list($response, 'asset_details', array());
            $result = array();
            for ($i = 0; $i < count($data); $i++) {
                $entry = $data[$i];
                $id = $this->safe_string($entry, 'asset_id');
                $code = $this->safe_currency_code($this->safe_string($entry, 'symbol'));
                $decimals = $this->safe_string($entry, 'decimals');
                $isUSDC = ($code === 'USDC');
                $depositMin = null;
                $withdrawMin = null;
                if ($isUSDC) {
                    $depositMin = $this->safe_number($entry, 'min_transfer_amount');
                    $withdrawMin = $this->safe_number($entry, 'min_withdrawal_amount');
                }
                $result[$code] = $this->safe_currency_structure(array(
                    'id' => $id,
                    'name' => $code,
                    'code' => $code,
                    'precision' => $this->parse_number('1e-' . $decimals),
                    'active' => true,
                    'fee' => null,
                    'networks' => array(),
                    'deposit' => $isUSDC,
                    'withdraw' => $isUSDC,
                    'type' => 'crypto',
                    'limits' => array(
                        'deposit' => array(
                            'min' => $depositMin,
                            'max' => null,
                        ),
                        'withdraw' => array(
                            'min' => $withdrawMin,
                            'max' => null,
                        ),
                    ),
                    'info' => $entry,
                ));
            }
            return $result;
        }) ();
    }

    public function fetch_order_book(string $symbol, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $limit, $params) {
            /**
