            Async\await($this->load_markets());
            $market = $this->market($symbol);
            $request = array(
                'market_id' => $market['id'],
                'limit' => 100,
            );
            if ($limit !== null) {
                $request['limit'] = min ($limit, 100);
            }
            $response = Async\await($this->publicGetOrderBookOrders ($this->extend($request, $params)));
