            //         "bids" => array(
            //             {
            //                 "order_index" => 562949401225099,
            //                 "order_id" => "562949401225099",
            //                 "owner_account_index" => 314236,
            //                 "initial_base_amount" => "1.7361",
            //                 "remaining_base_amount" => "1.3237",
            //                 "price" => "3429.80",
            //                 "order_expiry" => 1765419047587
