            //                 "exchange" => "lighter",
            //                 "symbol" => "ETH",
            //                 "rate" => 0.00009599999999999999
            //             }
            //         )
            //     }
            //
            $data = $this->safe_list($response, 'funding_rates', array());
            $result = array();
