    public function parse_position(array $position, ?array $market = null) {
        //
        //     {
        //         "market_id" => 0,
        //         "symbol" => "ETH",
        //         "initial_margin_fraction" => "5.00",
        //         "open_order_count" => 0,
        //         "pending_order_count" => 0,
        //         "position_tied_order_count" => 0,
        //         "sign" => 1,
        //         "position" => "18.0193",
        //         "avg_entry_price" => "2669.84",
        //         "position_value" => "54306.566340",
        //         "unrealized_pnl" => "6197.829558",
        //         "realized_pnl" => "0.000000",
        //         "liquidation_price" => "2191.1107231380406",
        //         "margin_mode" => 0,
        //         "allocated_margin" => "0.000000"
        //     }
        //
        $marketId = $this->safe_string($position, 'market_id');
        $market = $this->safe_market($marketId, $market);
        $sign = $this->safe_integer($position, 'sign');
        $side = null;
        if ($sign !== null) {
            $side = ($sign === 1) ? 'long' : 'short';
        }
        $marginModeId = $this->safe_integer($position, 'margin_mode');
        $marginMode = null;
        if ($marginModeId !== null) {
            $marginMode = ($marginModeId === 0) ? 'cross' : 'isolated';
        }
        $imfStr = $this->safe_string($position, 'initial_margin_fraction');
        $leverage = null;
        if ($imfStr !== null) {
            $imf = $this->parse_to_int($imfStr);
            if ($imf > 0) {
                $leverage = 100 / $imf;
            }
        }
        return $this->safe_position(array(
            'info' => $position,
            'id' => null,
            'symbol' => $market['symbol'],
            'timestamp' => null,
            'datetime' => null,
            'isolated' => ($marginMode === 'isolated'),
            'hedged' => null,
            'side' => $side,
            'contracts' => $this->safe_number($position, 'position'),
            'contractSize' => null,
            'entryPrice' => $this->safe_number($position, 'avg_entry_price'),
            'markPrice' => null,
            'notional' => $this->safe_number($position, 'position_value'),
            'leverage' => $leverage,
            'collateral' => $this->safe_number($position, 'allocated_margin'),
            'initialMargin' => null,
            'maintenanceMargin' => null,
            'initialMarginPercentage' => null,
            'maintenanceMarginPercentage' => null,
            'unrealizedPnl' => $this->safe_number($position, 'unrealized_pnl'),
            'liquidationPrice' => $this->safe_number($position, 'liquidation_price'),
            'marginMode' => $marginMode,
            'percentage' => null,
        ));
    }

